Hello I found a workaround to this issue which I explain on stackoverflow here: https://stackoverflow.com/questions/78245462/keyboardlistener-is-buggy-after-focusing-a-textfield/78245463

I paste the example below, for full explanation go on stackoverflow:

```dart
import 'dart:io';

import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:flutter_barcode_listener/flutter_barcode_listener.dart';
import 'package:flutter_hooks/flutter_hooks.dart';

void main() => runApp(const MyApp());

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      theme: ThemeData(useMaterial3: true),
      home: const Root(),
    );
  }
}

class ScanReader extends HookWidget {
  final void Function(String value) onScan;

  const ScanReader({super.key, required this.onScan});

  @override
  Widget build(BuildContext context) {
    var controller = useState<TextEditingController>(TextEditingController());
    var keyboardShowed = useState<bool>(false);

    openKeyboard() {
      keyboardShowed.value = true;
      SystemChannels.textInput.invokeMethod("TextInput.show");
    }

    closeKeyboard() {
      keyboardShowed.value = false;
      SystemChannels.textInput.invokeMethod("TextInput.hide");
      controller.value.clear();
    }

    useEffect(() {
      thisHandle(KeyEvent keyEvent) {
        if (keyboardShowed.value == false) {
          return false;
        }
        if (keyEvent.logicalKey == LogicalKeyboardKey.backspace &&
            controller.value.text.isNotEmpty) {
          controller.value.text = controller.value.text
              .substring(0, controller.value.text.length - 1);
        } else if (keyEvent.logicalKey == LogicalKeyboardKey.enter) {
          onScan(controller.value.text);
          closeKeyboard();
        } else {
          var newChar = keyEvent.character.toString();
          if (newChar.length == 1) {
            controller.value.text += newChar;
          }
        }
        return true;
      }

      HardwareKeyboard.instance.addHandler(thisHandle);
      return () {
        HardwareKeyboard.instance.removeHandler(thisHandle);
      };
    }, []);

    return Column(
      children: <Widget>[
        BarcodeKeyboardListener(
          bufferDuration: const Duration(milliseconds: 200),
          onBarcodeScanned: (newBarcode) {
            if (newBarcode != '') {
              onScan(newBarcode);
            }
          },
          useKeyDownEvent: Platform.isWindows,
          child: TextField(
            autofocus: false,
            readOnly: true,
            keyboardType: TextInputType.text,
            controller: controller.value,
            decoration: InputDecoration(
              suffixIcon: IconButton(
                icon: const Icon(Icons.close),
                onPressed: () {
                  closeKeyboard();
                },
              ),
              hintText: 'Search...',
            ),
            onTap: () {
              openKeyboard();
            },
          ),
        ),
      ],
    );
  }
}

class Root extends HookWidget {
  const Root({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {

    return SafeArea(
      child: Scaffold(
        body: ScanReader(onScan: (String value) {
          print('$value');
        }),
      ),
    );
  }
}
